311	    /// Create HTTP client with TLS/mTLS configuration
312	    fn with_client(mut self, config: &RouterConfig, timeout_secs: u64) -> Result<Self, String> {
313	        // FIXME: Current implementation creates a single HTTP client for all workers.
314	        // This works well for single security domain deployments where all workers share
315	        // the same CA and can accept the same client certificate.
316	        //
317	        // For multi-domain deployments (e.g., different model families with different CAs),
318	        // this architecture needs significant refactoring:
319	        // 1. Move client creation into worker registration workflow (per-worker clients)
320	        // 2. Store client per worker in WorkerRegistry
321	        // 3. Update PDRouter and other routers to fetch client from worker
322	        // 4. Add per-worker TLS spec in WorkerConfigRequest
323	        //
324	        // Current single-domain approach is sufficient for most deployments.
325	        //
326	        // Use rustls TLS backend when TLS/mTLS is configured (client cert or CA certs provided).
327	        // This ensures proper PKCS#8 key format support. For plain HTTP workers, use default
328	        // backend to avoid unnecessary TLS initialization overhead.
329	        let has_tls_config = config.client_identity.is_some() || !config.ca_certificates.is_empty();
330	
331	        let mut client_builder = Client::builder()
332	            .pool_idle_timeout(Some(Duration::from_secs(config.pool_idle_timeout_secs)))
333	            .pool_max_idle_per_host(config.pool_max_idle_per_host)
334	            .timeout(Duration::from_secs(timeout_secs))
335	            .connect_timeout(Duration::from_secs(config.connect_timeout_secs))
336	            .tcp_nodelay(true)
337	            .tcp_keepalive(Some(Duration::from_secs(config.tcp_keepalive_secs)));
338	
339	        // Force rustls backend when TLS is configured
340	        if has_tls_config {
341	            client_builder = client_builder.use_rustls_tls();
342	            debug!("Using rustls TLS backend for TLS/mTLS connections");
343	        }
344	
345	        // Configure mTLS client identity if provided (certificates already loaded during config creation)
346	        if let Some(identity_pem) = &config.client_identity {
347	            let identity = reqwest::Identity::from_pem(identity_pem)
348	                .map_err(|e| format!("Failed to create client identity: {}", e))?;
349	            client_builder = client_builder.identity(identity);
350	            debug!("mTLS client authentication enabled");
351	        }
352	
353	        // Add CA certificates for verifying worker TLS (certificates already loaded during config creation)
354	        for ca_cert in &config.ca_certificates {
355	            let cert = reqwest::Certificate::from_pem(ca_cert)
356	                .map_err(|e| format!("Failed to add CA certificate: {}", e))?;
357	            client_builder = client_builder.add_root_certificate(cert);
358	        }
359	        if !config.ca_certificates.is_empty() {
360	            debug!(
361	                "Added {} CA certificate(s) for worker verification",
362	                config.ca_certificates.len()
363	            );
364	        }
365	
366	        let client = client_builder
367	            .build()
368	            .map_err(|e| format!("Failed to create HTTP client: {}", e))?;
369	
370	        self.client = Some(client);
371	        Ok(self)
372	    }
