1	//! Async job queue for control plane operations
2	//!
3	//! Provides non-blocking worker management by queuing operations and processing
4	//! them asynchronously in background worker tasks.
5	
6	use std::{
7	    collections::HashMap,
8	    sync::{Arc, Weak},
9	    time::{Duration, SystemTime},
10	};
11	
12	use dashmap::DashMap;
13	use smg_mcp::McpConfig;
14	use tokio::sync::{mpsc, Semaphore};
15	use tracing::{debug, error, info, warn};
16	use wfaas::WorkflowId;
17	
18	use crate::{
19	    app_context::AppContext,
20	    config::{RouterConfig, RoutingMode},
21	    core::steps::{
22	        create_external_worker_workflow_data, create_local_worker_workflow_data,
23	        create_mcp_workflow_data, create_tokenizer_workflow_data,
24	        create_wasm_registration_workflow_data, create_wasm_removal_workflow_data,
25	        create_worker_removal_workflow_data, create_worker_update_workflow_data,
26	        McpServerConfigRequest, TokenizerConfigRequest, TokenizerRemovalRequest,
27	        WasmModuleConfigRequest, WasmModuleRemovalRequest,
28	    },
29	    protocols::worker_spec::{JobStatus, WorkerConfigRequest, WorkerUpdateRequest},
30	};
31	
32	/// Job types for control plane operations
33	#[derive(Debug, Clone)]
34	pub enum Job {
35	    AddWorker {
36	        config: Box<WorkerConfigRequest>,
37	    },
38	    UpdateWorker {
39	        url: String,
40	        update: Box<WorkerUpdateRequest>,
41	    },
42	    RemoveWorker {
43	        url: String,
44	    },
45	    InitializeWorkersFromConfig {
46	        router_config: Box<RouterConfig>,
