120	/// Job queue manager for worker validation and removal operations
121	pub struct JobQueue {
122	    /// Channel for submitting jobs
123	    tx: mpsc::Sender<Job>,
124	    /// Weak reference to AppContext to avoid circular dependencies
125	    context: Weak<AppContext>,
126	    /// Job status tracking by worker URL
127	    status_map: Arc<DashMap<String, JobStatus>>,
128	    /// Semaphore to limit concurrent job execution
129	    concurrency_limit: Arc<Semaphore>,
130	}
131	
132	impl std::fmt::Debug for JobQueue {
133	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
134	        f.debug_struct("JobQueue")
135	            .field("status_count", &self.status_map.len())
136	            .finish()
