140	impl JobQueue {
141	    /// Create a new job queue with semaphore-based concurrency control
142	    ///
143	    /// Takes a Weak reference to AppContext to avoid circular strong references.
144	    /// Spawns a single dispatcher task that spawns individual job tasks with semaphore control.
145	    pub fn new(config: JobQueueConfig, context: Weak<AppContext>) -> Arc<Self> {
146	        let (tx, mut rx) = mpsc::channel(config.queue_capacity);
147	
148	        debug!(
149	            "Initializing job queue: capacity={}, max_concurrent={}",
150	            config.queue_capacity, config.max_concurrent_jobs
151	        );
152	
153	        let status_map = Arc::new(DashMap::new());
154	        let concurrency_limit = Arc::new(Semaphore::new(config.max_concurrent_jobs));
155	
156	        let queue = Arc::new(Self {
157	            tx,
158	            context: context.clone(),
159	            status_map: status_map.clone(),
160	            concurrency_limit: concurrency_limit.clone(),
161	        });
162	
163	        // Single dispatcher task
164	        let ctx = context.clone();
165	        let status = status_map.clone();
166	        let sem = concurrency_limit.clone();
167	
168	        tokio::spawn(async move {
169	            while let Some(job) = rx.recv().await {
170	                // Acquire permit (blocks if at concurrency limit)
171	                let Ok(permit) = sem.clone().acquire_owned().await else {
172	                    error!("Semaphore closed, stopping dispatcher");
173	                    break;
174	                };
175	
176	                let ctx_clone = ctx.clone();
177	                let status_clone = status.clone();
178	
179	                tokio::spawn(async move {
180	                    Self::process_job(job, ctx_clone, status_clone, permit).await;
181	                });
182	            }
183	
184	            debug!("Job dispatcher stopped");
185	        });
186	
187	        // Spawn cleanup task for old job statuses (TTL 5 minutes)
188	        let cleanup_status_map = status_map.clone();
189	        tokio::spawn(async move {
190	            Self::cleanup_old_statuses(cleanup_status_map).await;
191	        });
192	
193	        queue
194	    }
195	
196	    /// Get current queue and concurrency status
197	    pub fn get_load_info(&self) -> (usize, usize) {
198	        let queue_depth = self.tx.max_capacity() - self.tx.capacity();
199	        let available_permits = self.concurrency_limit.available_permits();
200	        (queue_depth, available_permits)
201	    }
202	
203	    /// Submit a job with detailed queue status
204	    pub async fn submit(&self, job: Job) -> Result<(), String> {
205	        // Check if context is still alive before accepting jobs
206	        if self.context.upgrade().is_none() {
207	            return Err("Job queue shutting down: AppContext dropped".to_string());
208	        }
209	
210	        // Extract values before moving job
211	        let job_type = job.job_type();
212	        let worker_url = job.worker_url().to_string();
213	
214	        // Record pending status
215	        self.status_map.insert(
216	            worker_url.clone(),
217	            JobStatus::pending(job_type, &worker_url),
218	        );
219	
220	        match self.tx.send(job).await {
221	            Ok(_) => {
222	                let (queue_depth, available_permits) = self.get_load_info();
223	                debug!(
224	                    "Job submitted: type={}, worker={}, queue_depth={}, available_slots={}",
225	                    job_type, worker_url, queue_depth, available_permits
226	                );
227	                Ok(())
228	            }
229	            Err(_) => {
230	                self.status_map.remove(&worker_url);
231	                let (queue_depth, _) = self.get_load_info();
232	                Err(format!(
233	                    "Job queue full: {} jobs pending (capacity: {})",
234	                    queue_depth,
235	                    self.tx.max_capacity()
236	                ))
237	            }
238	        }
239	    }
