241	    /// Get job status by worker URL
242	    pub fn get_status(&self, worker_url: &str) -> Option<JobStatus> {
243	        self.status_map.get(worker_url).map(|entry| entry.clone())
244	    }
245	
246	    /// Remove job status (called when worker is deleted)
247	    pub fn remove_status(&self, worker_url: &str) {
248	        self.status_map.remove(worker_url);
249	    }
