251	    /// Process a single job with status tracking and error handling
252	    async fn process_job(
253	        job: Job,
254	        context: Weak<AppContext>,
255	        status_map: Arc<DashMap<String, JobStatus>>,
256	        _permit: tokio::sync::OwnedSemaphorePermit,
257	    ) {
258	        let job_type = job.job_type();
259	        let worker_url = job.worker_url().to_string();
260	        let start = std::time::Instant::now();
261	
262	        // Update to processing
263	        status_map.insert(
264	            worker_url.clone(),
265	            JobStatus::processing(job_type, &worker_url),
266	        );
267	
268	        debug!("Processing job: type={}, worker={}", job_type, worker_url);
269	
270	        // Execute job
271	        match context.upgrade() {
272	            Some(ctx) => {
273	                let result = Self::execute_job(&job, &ctx).await;
274	                let duration = start.elapsed();
275	                Self::record_job_completion(job_type, &worker_url, duration, &result, &status_map);
276	            }
277	            None => {
278	                let error_msg = "AppContext dropped".to_string();
279	                status_map.insert(
280	                    worker_url.clone(),
281	                    JobStatus::failed(job_type, &worker_url, error_msg),
282	                );
283	                error!(
284	                    "AppContext dropped, cannot process job: type={}, worker={}",
285	                    job_type, worker_url
286	                );
287	            }
288	        }
289	
290	        // Permit automatically released when dropped
291	    }
