714	                    .await
715	                    .map_err(|e| {
716	                        format!("Failed to start tokenizer registration workflow: {:?}", e)
717	                    })?;
718	
719	                debug!(
720	                    "Started tokenizer registration workflow for '{}' id={} (instance: {})",
721	                    config.name, config.id, instance_id
722	                );
723	
724	                // Allow up to 10 minutes for HuggingFace downloads
